                <ul className="list-disc list-outside ml-4 space-y-1.5 marker:text-ink-400">
                  {job.description.map((desc, i) => (
                    <li key={i} className="text-sm text-ink-800 leading-relaxed">
                      {desc}
                    </li>
                  ))}
                </ul>
              </div>
            ))}
          </div>
        </div>
      </div>
    </Section>
  );
};

